 16	static int l_assert(bvm *vm)
 17	{
 18	    int argc = be_top(vm);
 19	    /* assertion fails when there is no argument
 20	     * or the first argument is nil or false. */
 21	    if (!argc || !be_tobool(vm, 1)) {
 22	        const char *msg = "assert failed!";
 23	        if (argc >= 2 && be_isstring(vm, 2)) {
 24	            msg = be_tostring(vm, 2);
 25	        }
 26	        be_raise(vm, "assert_failed", msg);
 27	    }
 28	    be_return_nil(vm);
 29	}
