 31	static int l_print(bvm *vm)
 32	{
 33	    int i, argc = be_top(vm);
 34	    for (i = 1; i <= argc; ++i) {
 35	        const char *str = be_tostring(vm, i);
 36	        size_t len = be_strlen(vm, i);
 37	        be_writebuffer(str, len);
 38	        if (i < argc) {
 39	            be_writebuffer(" ", 1);
 40	        }
 41	    }
 42	    be_writenewline();
 43	    be_return_nil(vm);
 44	}
 45	
 46	static int m_readline(bvm *vm)
 47	{
 48	    size_t pos = 0, size = READLINE_STEP;
 49	    char *buffer = be_malloc(vm, size);
 50	    char *res = be_readstring(buffer, (int)size);
 51	    while (res) {
 52	        pos += strlen(buffer + pos) - 1;
 53	        if (!pos || buffer[pos] == '\n') {
 54	            buffer[pos] = '\0'; /* trim \n */
 55	            break;
 56	        }
 57	        buffer = be_realloc(vm, buffer, size, size + READLINE_STEP);
 58	        res = be_readstring(buffer + pos + 1, READLINE_STEP);
 59	        size += READLINE_STEP;
 60	    }
 61	    be_pushstring(vm, buffer);
 62	    be_free(vm, buffer, size);
 63	    be_return(vm);
 64	}
